mapper.select:
select t.*
from pr_import_valve t
         inner join (
    select meter_num
    from pr_import_valve
    where company_id = #{companyId}
      and type = '0'
      and create_by = #{create}
    group by meter_num
    having count(1) > 1
) dup on t.meter_num = dup.meter_num
where t.company_id = #{companyId}
  and t.type = '0'
  and t.create_by = #{create}
limit 500

select count(1)
from pr_import_valve
where company_id = #{companyId}
  and create_by = #{create}
  and type = '0'

select org_name, building_name, room_num, '否' as 'isCommand'
from pr_house
where company_id = #{companyId}
  and org_id = #{orgId}
  and del_flag = '0'

mapper.delete:
delete
from pr_import_valve
where company_id = #{companyId}
  and create_by = #{create}
  and type = '0'

delete
from pr_import_valve
where company_id = #{companyId}
  and create_by = #{create}

delete a
from pr_heat_valve_archive a
         left join pr_house b on b.id = a.house_id
    and b.company_id = #{companyId}
    and b.org_id in (
    select distinct org_id
    from pr_import_valve
    where company_id = #{companyId}
      and create_by = #{create}
      and type = '0'
)
where a.company_id = #{companyId}
  and a.org_id in (
    select distinct org_id
    from pr_import_valve
    where company_id = #{companyId}
      and create_by = #{create}
      and type = '0'
)
  and a.house_id is not null
  and b.id is null
